     7→use config::Config;
     8→use presence::PresenceKeeper;
     9→use std::sync::atomic::{AtomicBool, Ordering};
    10→use std::sync::Mutex;
    11→use tauri::{Manager, RunEvent, WindowEvent};
    12→
    13→static SHOULD_EXIT: AtomicBool = AtomicBool::new(false);
    14→
    15→pub fn request_exit() {
    16→    SHOULD_EXIT.store(true, Ordering::SeqCst);
    17→}
    18→
    19→#[cfg(target_os = "macos")]
    20→use tauri::ActivationPolicy;
    21→
    22→pub struct AppState {
    23→    pub keeper: Mutex<PresenceKeeper>,
    24→    pub config: Mutex<Config>,
    25→}
    26→
    27→#[tauri::command]
    28→fn get_config(state: tauri::State<AppState>) -> Config {
    29→    state.config.lock().unwrap().clone()
    30→}
    31→
    32→#[tauri::command]
    33→fn save_config(state: tauri::State<AppState>, config: Config) -> Result<(), String> {
    34→    config.save()?;
    35→
    36→    // Update running keeper with new config
    37→    let mut keeper = state.keeper.lock().unwrap();
    38→    keeper.update_config(config.clone());
    39→
    40→    // Update stored config
    41→    let mut stored_config = state.config.lock().unwrap();
    42→    *stored_config = config;
    43→
    44→    Ok(())
    45→}
    46→
    47→#[tauri::command]
    48→fn toggle_enabled(state: tauri::State<AppState>) -> bool {
    49→    let mut keeper = state.keeper.lock().unwrap();
    50→    if keeper.is_running() {
    51→        keeper.stop();
    52→        false
    53→    } else {
    54→        keeper.start();
    55→        true
    56→    }
    57→}
    58→
    59→#[cfg_attr(mobile, tauri::mobile_entry_point)]
    60→pub fn run() {
    61→    let config = Config::load();
    62→    let keeper = PresenceKeeper::new(config.clone());
    63→
    64→    tauri::Builder::default()
    65→        .plugin(tauri_plugin_shell::init())
    66→        .manage(AppState {
    67→            keeper: Mutex::new(keeper),
    68→            config: Mutex::new(config),
    69→        })
    70→        .invoke_handler(tauri::generate_handler![get_config, save_config, toggle_enabled])
    71→        .setup(|app| {
    72→            // Hide dock icon on macOS (tray-only app)
    73→            #[cfg(target_os = "macos")]
    74→            app.set_activation_policy(ActivationPolicy::Accessory);
    75→
    76→            // Start input monitor for idle detection
    77→            if let Err(e) = input_monitor::start_input_monitor() {
    78→                eprintln!("[Setup] Failed to start input monitor: {}", e);
    79→            }
    80→
    81→            // Create system tray
    82→            tray::create_tray(app.handle())?;
    83→
    84→            // Auto-start the keeper if enabled
    85→            let state = app.state::<AppState>();
    86→            let config = state.config.lock().unwrap();
    87→            if config.enabled {
    88→                let mut keeper = state.keeper.lock().unwrap();
    89→                keeper.start();
    90→            }
    91→
    92→            // Hide window on startup (tray-only app)
    93→            if let Some(window) = app.get_webview_window("main") {
    94→                let _ = window.hide();
    95→            }
    96→
    97→            Ok(())
    98→        })
    99→        .build(tauri::generate_context!())
   100→        .expect("error while building tauri application")
   101→        .run(|app_handle, event| {
   102→            match event {
   103→                RunEvent::WindowEvent {
   104→                    label,
   105→                    event: WindowEvent::CloseRequested { api, .. },
   106→                    ..
   107→                } => {
   108→                    // Prevent the window from being destroyed, just hide it
   109→                    api.prevent_close();
   110→                    if let Some(window) = app_handle.get_webview_window(&label) {
   111→                        let _ = window.hide();
   112→                    }
   113→                }
   114→                RunEvent::ExitRequested { api, .. } => {
   115→                    // Only prevent exit if we don't want to quit
   116→                    if !SHOULD_EXIT.load(Ordering::SeqCst) {
   117→                        api.prevent_exit();
   118→                    }
   119→                }
   120→                _ => {}
   121→            }
   122→        });
   123→}
