     8→
     9→static ICON_ACTIVE: OnceLock<Image<'static>> = OnceLock::new();
    10→static ICON_INACTIVE: OnceLock<Image<'static>> = OnceLock::new();
    11→
    12→fn get_cached_icon(is_active: bool) -> &'static Image<'static> {
    13→    if is_active {
    14→        ICON_ACTIVE.get_or_init(|| {
    15→            Image::from_bytes(include_bytes!("../icons/tray-active.png"))
    16→                .expect("Failed to decode tray-active.png")
    17→        })
    18→    } else {
    19→        ICON_INACTIVE.get_or_init(|| {
    20→            Image::from_bytes(include_bytes!("../icons/tray-inactive.png"))
    21→                .expect("Failed to decode tray-inactive.png")
    22→        })
    23→    }
    24→}
    25→
    26→fn update_tray_icon<R: Runtime>(tray: &TrayIcon<R>, is_active: bool) {
    27→    let _ = tray.set_icon(Some(get_cached_icon(is_active).clone()));
    28→}
    29→
    30→pub fn create_tray<R: Runtime>(app: &AppHandle<R>) -> tauri::Result<()> {
    31→    let toggle_i = MenuItem::with_id(app, "toggle", "Disable", true, None::<&str>)?;
    32→    let separator0 = PredefinedMenuItem::separator(app)?;
    33→    let resume_i = MenuItem::with_id(app, "resume", "Resume", false, None::<&str>)?;
    34→    let pause_30_i = MenuItem::with_id(app, "pause_30", "Pause 30 min", true, None::<&str>)?;
    35→    let pause_60_i = MenuItem::with_id(app, "pause_60", "Pause 1 hour", true, None::<&str>)?;
    36→    let separator1 = PredefinedMenuItem::separator(app)?;
    37→    let settings_i = MenuItem::with_id(app, "settings", "Settings...", true, None::<&str>)?;
    38→    let separator2 = PredefinedMenuItem::separator(app)?;
    39→    let quit_i = MenuItem::with_id(app, "quit", "Quit", true, None::<&str>)?;
    40→
    41→    let menu = Menu::with_items(
    42→        app,
    43→        &[
    44→            &toggle_i,
    45→            &separator0,
    46→            &resume_i,
    47→            &pause_30_i,
    48→            &pause_60_i,
    49→            &separator1,
    50→            &settings_i,
    51→            &separator2,
    52→            &quit_i,
    53→        ],
    54→    )?;
    55→
    56→    let icon = Image::from_bytes(include_bytes!("../icons/tray-active.png"))
    57→        .expect("Failed to load tray icon");
    58→
    59→    // Show "DEV" label next to icon in debug builds to distinguish from production
    60→    #[cfg(debug_assertions)]
    61→    let tray_title = Some("DEV");
    62→    #[cfg(not(debug_assertions))]
    63→    let tray_title: Option<&str> = None;
    64→
    65→    let mut builder = TrayIconBuilder::with_id("main")
    66→        .icon(icon)
    67→        .icon_as_template(false)
    68→        .menu(&menu)
    69→        .show_menu_on_left_click(true);
    70→
    71→    // Set title only in dev mode (shows text next to icon on macOS)
    72→    if let Some(title) = tray_title {
    73→        builder = builder.title(title);
    74→    }
    75→
    76→    let _ = builder
    77→        .on_menu_event(move |app, event| {
    78→            // Helper to update pause-related menu items
    79→            let update_pause_menu = |is_paused: bool, remaining: Option<u32>| {
    80→                if is_paused {
    81→                    if let Some(mins) = remaining {
    82→                        let _ = resume_i.set_text(&format!("Resume ({} min left)", mins));
    83→                    } else {
    84→                        let _ = resume_i.set_text("Resume");
    85→                    }
    86→                    let _ = resume_i.set_enabled(true);
    87→                    let _ = pause_30_i.set_enabled(false);
    88→                    let _ = pause_60_i.set_enabled(false);
    89→                } else {
    90→                    let _ = resume_i.set_text("Resume");
    91→                    let _ = resume_i.set_enabled(false);
    92→                    let _ = pause_30_i.set_enabled(true);
    93→                    let _ = pause_60_i.set_enabled(true);
    94→                }
    95→            };
    96→
    97→            // Update menu state when menu event occurs
    98→            {
    99→                let state = app.state::<crate::AppState>();
   100→                let keeper = state.keeper.lock().unwrap();
   101→                let is_running = keeper.is_running();
   102→
   103→                // Update toggle text
   104→                if is_running {
   105→                    let _ = toggle_i.set_text("Disable");
   106→                } else {
   107→                    let _ = toggle_i.set_text("Enable");
   108→                }
   109→
   110→                // Update tray icon to reflect current state
   111→                if let Some(tray) = app.tray_by_id("main") {
   112→                    update_tray_icon(&tray, is_running);
   113→                }
   114→
   115→                // Update pause status
   116→                update_pause_menu(keeper.is_paused(), keeper.pause_remaining_minutes());
   117→            }
   118→
   119→            match event.id.as_ref() {
   120→                "toggle" => {
   121→                    let state = app.state::<crate::AppState>();
   122→                    let mut keeper = state.keeper.lock().unwrap();
   123→                    if keeper.is_running() {
   124→                        keeper.stop();
   125→                        let _ = toggle_i.set_text("Enable");
   126→                    } else {
   127→                        keeper.start();
   128→                        let _ = toggle_i.set_text("Disable");
   129→                    }
   130→                    // Update tray icon to reflect the new state (read after toggle)
   131→                    let new_state = keeper.is_running();
   132→                    if let Some(tray) = app.tray_by_id("main") {
   133→                        update_tray_icon(&tray, new_state);
   134→                    }
   135→                }
   136→                "resume" => {
   137→                    let state = app.state::<crate::AppState>();
   138→                    let mut keeper = state.keeper.lock().unwrap();
   139→                    keeper.resume();
   140→                    update_pause_menu(false, None);
   141→                }
   142→                "pause_30" => {
   143→                    let state = app.state::<crate::AppState>();
   144→                    let mut keeper = state.keeper.lock().unwrap();
   145→                    keeper.pause(30);
   146→                    update_pause_menu(true, Some(30));
   147→                }
   148→                "pause_60" => {
   149→                    let state = app.state::<crate::AppState>();
   150→                    let mut keeper = state.keeper.lock().unwrap();
   151→                    keeper.pause(60);
   152→                    update_pause_menu(true, Some(60));
   153→                }
   154→                "settings" => {
   155→                    if let Some(window) = app.get_webview_window("main") {
   156→                        let _ = window.show();
   157→                        let _ = window.set_focus();
   158→                    }
   159→                }
   160→                "quit" => {
   161→                    let state = app.state::<crate::AppState>();
   162→                    let mut keeper = state.keeper.lock().unwrap();
   163→                    keeper.stop();
   164→                    drop(keeper);
   165→                    crate::request_exit();
   166→                    app.exit(0);
   167→                }
   168→                _ => {}
   169→            }
   170→        })
   171→        .build(app)?;
   172→
   173→    Ok(())
   174→}
   175→

